13	  const candidates = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const key = keyOf(neighbor);
19	      const entry = candidates.get(key);
20	      if (entry) {
21	        entry.count++;
22	      } else {
