export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(keyOf));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = keyOf(neighbor);
      const entry = candidates.get(key);
      if (entry) {
        entry.count++;
      } else {
        candidates.set(key, { cell: neighbor, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of candidates) {
    if (count === 3 || (count === 2 && liveSet.has(key))) {
      result.push(cell);
    }
  }
  return result;
}

